-- =========================================================
-- VERIFICATION
-- =========================================================

SELECT
  pc.name                                   AS category,
  pm.name                                   AS product,
  COUNT(DISTINCT pi.id)                     AS variants,
  COUNT(DISTINCT pmmg.modifier_group_id)    AS modifiers,
  STRING_AGG(DISTINCT pi.name, ', '
    ORDER BY pi.name)                       AS sizes
FROM product_models pm
JOIN product_items pi
  ON pi.product_model_id = pm.id
LEFT JOIN product_model_modifier_groups pmmg
  ON pmmg.product_model_id = pm.id
LEFT JOIN product_categories pc
  ON pc.id = pm.category_id
WHERE pm.id::text LIKE 'c1000000%'
GROUP BY pc.name, pm.name
ORDER BY pc.name, pm.name;

COMMIT;